mapper.select:
SELECT /* @SQLID=EXTAPI_01-001#selectA001Branch */ B.BRANCH_CODE, B.BRANCH_KIND, B.BRANCH_NAME, TO_CHAR(B.CREATE_DATE, 'yyyyMMddHH24miss') CREATE_DATE, B.CREATE_BY, TO_CHAR(B.UPDATE_DATE, 'yyyyMMddHH24miss') UPDATE_DATE, B.UPDATE_BY, TO_CHAR(B.DELETE_DATE, 'yyyyMMddHH24miss') DELETE_DATE, B.DELETE_FLG FROM BRANCH B WHERE 1 = 0 OR (B.DELETE_FLG = '0'
AND B.BRANCH_KIND = #{req.branchKind}
) ORDER BY B.BRANCH_CODE ASC

SELECT /* @SQLID=EXTAPI_01-002#selectA002Broker */ DISTINCT BMI.BRANCH_CODE, MB.BROKER_CODE, MB.BROKER_BRANCH_CODE, MB.BROKER_BRANCH_KIND, MB.BRANCH_NAME As BROKER_BRANCH_NAME FROM BRANCH_MEDIATE_INFO BMI INNER JOIN MEDIATE_BRANCH MB ON BMI.BROKER_CODE = MB.BROKER_CODE AND MB.BROKER_BRANCH_KIND = '00' AND MB.DELETE_FLG = '0' AND BMI.DELETE_FLG = '0'
AND BMI.BRANCH_CODE = #{req.branchCode}
ORDER BY MB.BROKER_CODE ASC, MB.BROKER_BRANCH_CODE ASC

SELECT /* @SQLID=EXTAPI_01-003#selectA003Broker */ DISTINCT MB.BROKER_CODE, MB.BROKER_BRANCH_CODE, MB.BRANCH_NAME As BROKER_BRANCH_NAME FROM MEDIATE_BRANCH MB WHERE MB.DELETE_FLG = '0' AND MB.BROKER_BRANCH_KIND != '00'
AND MB.BROKER_CODE = #{req.brokerCode}
ORDER BY MB.BROKER_BRANCH_CODE ASC

SELECT /* @SQLID=EXTAPI_01-004#selectA004Employee */ MCI.BROKER_CODE, MCI.BROKER_BRANCH_CODE, MCI.BROKER_CHARGE_CODE As EMPLOYEE_ID, MCI.BROKER_CHARGE_NAME As EMPLOYEE_NAME FROM MEDIATE_CHARGE_INFO MCI WHERE MCI.DELETE_FLG = '0'
AND MCI.BROKER_CODE = #{req.brokerCode}
AND MCI.BROKER_BRANCH_CODE = #{req.brokerBranchCode}
